from pathlib import Path
import re
root = Path('.')
skip_dirs = {'.git', 'node_modules', '.yarn', 'dist', '.build', 'playwright-report', 'test-results', '.pnpm-store'}
target_suffixes = {'.js', '.ts', '.tsx', '.jsx', '.mjs', '.cjs', '.mts', '.cts'}
pattern_line = re.compile(r'(?im)^[\t ]*//[^\n]*eslint[^\n]*\n')
pattern_inline = re.compile(r'[\t ]*//[^\n]*eslint[^\n]*', re.IGNORECASE)
pattern_block = re.compile(r'/\*.*?eslint.*?\*/', re.IGNORECASE | re.DOTALL)
count = 0
for path in root.rglob('*'):
    if not path.is_file():
        continue
    if any(part in skip_dirs for part in path.parts):
        continue
    if path.suffix.lower() not in target_suffixes:
        continue
    try:
        text = path.read_text(encoding='utf-8')
    except UnicodeDecodeError:
        continue
    if 'eslint' not in text and 'ESLint' not in text:
        continue
    new_text = pattern_line.sub('\n', text)
    new_text = pattern_block.sub('', new_text)
    new_text = pattern_inline.sub('', new_text)
    if new_text != text:
        path.write_text(new_text, encoding='utf-8')
        count += 1
print(count)
PY"],"workdir":"/Users/duhl/git/anedot-frontend"}

